const SKILL_LESSONS = {"Nature des mots":"Repère le rôle du mot : déterminant devant un nom, adjectif pour préciser le nom, adverbe pour préciser un verbe ou un adjectif.","Sujet du verbe":"Pose la question « qui est-ce qui ? » avant le verbe.","COD":"Pose « qui ? » ou « quoi ? » après le verbe, sans préposition.","Types de phrases":"Déclarative : informe ; interrogative : questionne ; injonctive : ordonne ; exclamative : exprime une émotion.","Phrase simple et complexe":"Une phrase simple contient un seul verbe conjugué ; une phrase complexe en contient plusieurs.","Présent de l’indicatif":"Vérifie la terminaison selon le sujet et le groupe du verbe.","Imparfait":"Terminaisons : -ais, -ais, -ait, -ions, -iez, -aient.","Futur simple":"On utilise généralement l’infinitif suivi de -ai, -as, -a, -ons, -ez, -ont.","Passé composé":"Auxiliaire être ou avoir au présent + participe passé.","Accord sujet-verbe":"Le verbe s’accorde toujours avec son sujet, même si les deux sont éloignés.","Homophones a / à":"Remplace « a » par « avait ». Si la phrase fonctionne, écris « a » ; sinon « à ».","Homophones et / est":"Remplace « est » par « était ». Si cela fonctionne, écris « est ».","Homophones son / sont":"Remplace « sont » par « étaient ». Si cela fonctionne, écris « sont ».","Accord dans le groupe nominal":"Déterminant, nom et adjectif s’accordent en genre et en nombre.","Pluriel des noms":"Attention aux pluriels particuliers : cheval/chevaux, jeu/jeux, journal/journaux.","Synonymes":"Deux synonymes ont un sens proche.","Antonymes":"Deux antonymes ont des sens opposés.","Familles de mots":"Les mots d’une même famille ont un radical commun et un sens lié.","Sens propre et figuré":"Le sens propre est concret ; le sens figuré est imagé."};
